import{_ as s,o as i,c as a,a4 as n}from"./chunks/framework.Cqne-ChA.js";const u=JSON.parse('{"title":"Developing zopen community","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/developing.md","filePath":"Guides/developing.md","lastUpdated":1776677767000}'),t={name:"Guides/developing.md"};function l(o,e,p,r,h,d){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="developing-zopen-community" tabindex="-1">Developing zopen community <a class="header-anchor" href="#developing-zopen-community" aria-label="Permalink to &quot;Developing zopen community&quot;">​</a></h1><p>Please read <a href="./QuickStart">Quick Start</a> and <a href="./ThePackageManager">The package manager</a> if you haven&#39;t already done so.</p><h2 id="zopen-directory-structure" tabindex="-1">zopen directory structure <a class="header-anchor" href="#zopen-directory-structure" aria-label="Permalink to &quot;zopen directory structure&quot;">​</a></h2><p>After running <code>zopen init</code>, you are able to install tools under the tools directory you chose, i.e. <code>$ZOPEN_ROOTFS</code></p><p>You can develop zopen community out of any directory you want. For example, if you wanted to make enhancements to the git port, you would perform the following commands:</p><ul><li>Install git:</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/zopen/etc/zopen-config</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # source zopen-config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Make sure you have git installed</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li>Clone repo</li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Before cloning, make sure to configure your git tag <a href="./GitOnZOS#file-tag-verifications">here</a></p></div><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com:zopencommunity/gitport.git</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # clone the z/OS git port</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Build application</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gitport</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # perform a build of git</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># make changes to the git source...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # repeat zopen build command</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>This will build <code>gitport</code> and then install it into the <code>$ZOPEN_PKGINSTALL/zopen/git</code> directory. This will set git as the active version in your zopen installation. You can use <code>zopen alt</code> to customize which version of git to set as the active version. Invoke <code>zopen alt --help</code> for details on how to customize this.</p><h2 id="using-the-zopen-commands" tabindex="-1">Using the zopen commands <a class="header-anchor" href="#using-the-zopen-commands" aria-label="Permalink to &quot;Using the zopen commands&quot;">​</a></h2><p>To see the list of commands:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="developing-zopen-community-1" tabindex="-1">Developing zopen community <a class="header-anchor" href="#developing-zopen-community-1" aria-label="Permalink to &quot;Developing zopen community&quot;">​</a></h2><h3 id="zopen-generate" tabindex="-1">zopen generate <a class="header-anchor" href="#zopen-generate" aria-label="Permalink to &quot;zopen generate&quot;">​</a></h3><p>If you&#39;re starting a new port, it is advised that you start with the <code>zopen generate</code> command. <code>zopen generate</code> will prompt for a series of questions and then generate a file and directory structure, including a <code>buildenv</code> file which will be used as input to the <code>zopen build</code> command.</p><h3 id="zopen-build" tabindex="-1">zopen build <a class="header-anchor" href="#zopen-build" aria-label="Permalink to &quot;zopen build&quot;">​</a></h3><p>To build a software package, you can use <code>zopen build</code>.</p><p><code>zopen build</code> requires the files scripts in the project&#39;s root directory:</p><ul><li><code>buildenv</code>, which <code>zopen build</code> will automatically source. If you would like to source another file, you can specify it via the <code>-e</code> option as in: <code>zopen build -e mybuildenv</code></li></ul><p>The <code>buildenv</code> file <em>must</em> set the following environment variables:</p><ul><li><code>ZOPEN_BUILD_LINE</code>: one of DEV or STABLE indicating which build line to build off of.</li><li><code>ZOPEN_DEV_URL</code> or <code>ZOPEN_STABLE_URL</code>: the URL where the source should be pulled from, including the <code>package.git</code> or <code>package-V.R.M.tar.gz</code> extension</li><li><code>ZOPEN_DEV_DEPS</code> or <code>ZOPEN_STABLE_DEPS</code>: a space-separated list of all software dependencies this package has. These packages will automatically be downloaded if they are not present in your <code>$HOME/zopen/prod</code> or <code>$HOME/zopen/boot</code> directories.</li></ul><p>To determine the build quality of the port, a <code>zopen_check_results()</code> function needs to be provided inside <em>buildenv</em>. This function should process the test results and emit a report of the failures, total number of tests, expected number of failures and expected number of tests to stdout as in the following format:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">actualFailures:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;numberoffailures&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">totalTests:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;totalnumberoftests&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">expectedFailures:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;expectednumberoffailures&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">expectedTotalTests:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;expectednumberoftests&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The build will fail to proceed to the install step if <code>totalTests</code> is less than <code>expectedTotalTests</code> or if <code>actualFailures</code> is greater than <code>expectedFailures</code>.</p><p>Here is an example implementation of <code>zopen_check_results()</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen_check_results</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chk</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$2_check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.log&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">failures</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.* Test.*in .* Categories Failed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${chk} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39; &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">totalTests</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.* Test.*in .* Categories Failed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${chk} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39; &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ZZ</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">actualFailures:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$failures</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">totalTests:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$totalTests</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">expectedFailures:0</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">expectedTotalTests:1</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ZZ</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p><code>zopen build</code> will generate a .env file in the install location with support for environment variables such as PATH, LIBPATH, and MANPATH. To add your own, you can append environment variables by echo&#39;ing them in a function called <code>zopen_append_to_env()</code>.</p><p>After the build is successful, <code>zopen build</code> will install the project to <code>$HOME/zopen/prod/projectname</code>. To perform post-processing on the installed contents, such as modifying hardcoded path contents, you can write a <code>zopen_post_install()</code> function which takes the installed path as the first argument.</p><p>Note that you can choose the fully-qualified environment variables <code>ZOPEN_DEV_URL</code>, <code>ZOPEN_DEV_DEPS</code> and <code>ZOPEN_STABLE_URL</code>, <code>ZOPEN_STABLE_DEPS</code> accordingly if you prefer. See (<a href="https://github.com/zopencommunity/zotsampleport/blob/main/setenv.sh" target="_blank" rel="noreferrer">https://github.com/zopencommunity/zotsampleport/blob/main/setenv.sh</a>) for an example.</p><p>There are several additional environment variables that can be specified to provide finer-grained control of the build process. For details</p><ul><li>Run <code>zopen build -h</code> for a description of all the environment variables</li><li>Read the <a href="https://github.com/zopencommunity/meta/blob/main/bin/zopen-build" target="_blank" rel="noreferrer">code</a>.</li></ul><p>For a sample port, visit the <a href="https://github.com/zopencommunity/zotsampleport" target="_blank" rel="noreferrer">zotsampleport</a> repo.</p><h4 id="running-zopen-build" tabindex="-1">Running zopen build <a class="header-anchor" href="#running-zopen-build" aria-label="Permalink to &quot;Running zopen build&quot;">​</a></h4><p>Run <code>zopen build</code> from the root directory of the git repo you would like to build. For example, m4:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${HOME}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/zopen/dev/m4port</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="zopen-update-cacacert" tabindex="-1">zopen update-cacacert <a class="header-anchor" href="#zopen-update-cacacert" aria-label="Permalink to &quot;zopen update-cacacert&quot;">​</a></h3><p>To update the cacert.pem file, you can use <code>zopen update-cacert</code>. This will download the latest cacert.pem <a href="https://curl.se/docs/caextract.html" target="_blank" rel="noreferrer">file</a>. This cacert.pem file is then used by other tools such as <code>zopen install</code> and <code>zopen build</code>.</p><h3 id="zopen-importenvs" tabindex="-1">zopen-importenvs <a class="header-anchor" href="#zopen-importenvs" aria-label="Permalink to &quot;zopen-importenvs&quot;">​</a></h3><p>If you want to source the .env files from all of the installed zopen products under the zopen prod and boot directories, then you can use <code>zopen-importenvs</code>.</p><p>Usage of script is: <code>. ./zopen-importenvs</code></p><p>The path to buildenv is optional.</p><p>If the buildenv path is provided, the dependencies from the buildenv file are read and the env is sourced from prod/boot directory. This is useful if you want to have the same environment as zopen build in order to reproduce a problem with the build. Otherwise if the path is not provided then the .env from each project directory in the zopen prod/boot directories are sourced.</p>`,46)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
